scwin.f_ApproveSms = async function (e) {
  if (!(await scwin.f_Chk())) {
    //체크여부
    return;
  }
  if (txt_sendNo.getValue() == "") {
    await $c.win.alert($p, "발신번호를 입력하세요.");
    return;
  }
  if (!(await $c.gus.cfSmsTelValidChk($p, txt_sendNo.getValue()))) {
    return;
  }
  var chkRow = gr_oilInOut.getCheckedIndex('chk'); // 체크된 행의 인덱스

  for (var i = 0; i < chkRow.length; i++) {
    if (ds_oilInOut.getCellData(chkRow[i], "stsCd") != "2") {
      await $c.win.alert($p, $c.num.parseInt($p, chkRow[i] + 1) + "번째행은 발주상태가 아닙니다.");
      return false;
    }
  }
  for (var i = 0; i < chkRow.length; i++) {
    if (ds_oilInOut.getCellData(chkRow[i], "mpNo") == "") {
      await $c.win.alert($p, $c.num.parseInt($p, chkRow[i] + 1) + "번째행은 전화번호가 비어있습니다.전화번호를 입력하세요");
      return false;
    }
  }
  var cnt = 0;
  if (await $c.win.confirm($p, "SMS를 전송 하시겠습니까?")) {
    for (var i = 0; i < chkRow.length; i++) {
      if (ds_oilInOut.getCellData(chkRow[i], "stsCd") == "2") {
        ds_oilInOut.setCellData(chkRow[i], "sendNo", txt_sendNo.getValue());
        ds_oilInOut.setCellData(gr_oilInOut.getFocusedRowIndex(), 'smsSendDt', $c.date.getServerDateTime($p, "yyyyMMddHHmm"));
        cnt = cnt + 1;
      }
    }
    if (cnt > 0) {
      await scwin.submitdone(sbm_approveSms);
    }
  }
};

