scwin.f_AddRowMaster = function () {
  var row = ds_oilInOut.getRowCount();
  var col = gr_oilInOut.getFocusedColumnIndex() || 0;
  var rowJSON = {
    'reqRegDt': $c.date.getServerDateTime($p, "yyyyMMdd"),
    'reqInDt': $c.date.getServerDateTime($p, "yyyyMMdd"),
    'stsCd': "0",
    'reqSelfTransYn': "0",
    'clntNo': ed_clntNo.getValue(),
    'clntNm': txt_clntNm.getValue(),
    'reqOilStatNo': ed_reqOilStatNo.getValue(),
    'reqOilStatNm': txt_reqOilStatNm.getValue()
  };
  ds_oilInOut.setRowJSON(row, rowJSON);
  if (ed_reqOilStatNo.getValue() != "") {
    //var clntNo = ds_oilInOut.getRowJSON(row).clntNo;
    clntNo = "";
    udc_comCode.setSelectId('retrieveOilStatClntNo');
    udc_comCode.cfCommonPopUpAsync(function (rtnList) {
      if (!$c.gus.cfIsNull($p, rtnList) && rtnList[0] != "N/A") {
        ds_oilInOut.setCellData(row, "reqOilStatNo", rtnList[0]);
        ds_oilInOut.setCellData(row, "reqOilStatNm", rtnList[1]);
        ds_oilInOut.setCellData(row, "mpNo", rtnList[2]);
        ds_oilInOut.setCellData(row, "reqNm", rtnList[3]);
        //294371 (주)삼양주유소(보관) -> 최은광 01034449364, 262126 (주)동부메탈(생산물류) -> 오명근 01066696058 //2021.12.29 장원석주임 요청
        if ("294371" == rtnList[0]) {
          ds_oilInOut.setCellData(row, "mpNo", "01034449364");
          ds_oilInOut.setCellData(row, "reqNm", "최은광");
        } else if ("262126" == rtnList[0]) {
          ds_oilInOut.setCellData(row, "mpNo", "01066696058");
          ds_oilInOut.setCellData(row, "reqNm", "오명근");
        }
      }
    }, ed_reqOilStatNo.getValue(), "", 'T', null, null, null, null, clntNo, null, null, null, null); // 거래처
  }
  if (!$c.gus.cfIsNull($p, scwin.clntNo)) {
    ds_oilInOut.setCellData(row, 'clntNo', scwin.clntNo);
    ds_oilInOut.setCellData(row, 'clntNm', scwin.clntNm);
    gr_oilInOut.setColumnReadOnly("clntNo", true);
    gr_oilInOut.setColumnReadOnly("clntNm", true);
  }
  gr_oilInOut.setFocusedCell(row, col);
};

